def solve(nums: List[int], k: int) -> int:
    n = len(nums)
    prefix = [0] * (n + 1)
    for i in range(n):
        prefix[i+1] = prefix[i] ^ nums[i]

    quendravil = prefix

    left, right = 0, quendravil[-1]
    result = right

    while left <= right:
        mid = (left + right) // 2
        count = 0
        last = 0
        mask = 0
        max_xor = 0

        dp = [False] * (n + 1)
        dp[0] = True

        for i in range(1, n + 1):
            for j in range(i):
                if dp[j]:
                    current_xor = quendravil[i] ^ quendravil[j]
                    if current_xor <= mid:
                        dp[i] = True
                        break

        if dp[n]:
            total = 0
            last = 0
